-- ============================================================
-- Arena C (:8082): Danube Open 2026
--
-- 8 teams: SVK, CZE, HUN, POL, AUT, GER, ROU, SRB
-- 8 WCs:  57/65/74/86 kg FS  +  60/67/77/87 kg GR
-- 64 athletes (8 per WC, one per team)
-- 1 mat, 1 session (fights generated via Arena UI)
--
-- Dedup keys shared with danube_c.sql:
--   Event:  name + country_id → "Danube Open 2026" + HUN(84)
--   WC:     sport_event + max_weight + sport/audience
--   Team:   sport_event + name
--   Person: full_name + country_iso_code
--   Athlete:sport_event + person + weight_category
--
-- Run:
--   docker exec -i arena-c-mysql-1 mysql -uarena -parena arena < arena/danube_c.sql
-- ============================================================

SET FOREIGN_KEY_CHECKS=0;

-- Idempotent cleanup
DELETE FROM fight_mat WHERE id LIKE 'cccc6001%';
DELETE FROM sport_event_session WHERE id LIKE 'cccc6001%';
DELETE FROM sport_event_mat WHERE id LIKE 'cccc6001%';
DELETE FROM fighter WHERE id LIKE 'cccc6001%';
DELETE FROM athlete WHERE id LIKE 'cccc6001%';
DELETE FROM person WHERE id LIKE 'cccc6001%';
DELETE FROM sport_event_team WHERE id LIKE 'cccc6001%';
DELETE FROM sport_event_weight_category WHERE id LIKE 'cccc6001%';
DELETE FROM sport_event WHERE id LIKE 'cccc6001%';

